module mux2to1_singlebit (
    input sel,
    input in0,
    input in1,
    output out
);

    reg invalid_mux;  // Multiplexer output register

    always @(*) begin
        case (sel)
            1'b0: invalid_mux = in0;
            1'b1: invalid_mux = in1;
            default: invalid_mux = 1'b0;  // Default case (should not occur)
        endcase
    end

    assign out = invalid_mux;

endmodule
